<template>
  <div class="trans-report-wrapper container">
    <div v-if="loading" class="loading-overlay">
      <div class="overlay-content"><img src="@/assets/img/loading.gif" style="width: 60px" /></div>
    </div>
    <Header />
    <div class="content-wrapper">
      <div class="filter-toggle-wrapper" ref="toggleFilter">
        <span>
          <button class="filter-toggle" @click="toggleFilter()" :class="isFilterActive ? 'collasped' : ''">Search <fa :icon="['fas', 'angles-down']"></fa></button>
        </span>
        <div class="filter-wrapper" :class="[isFilterActive ? 'slide-in' : 'slide-out']">
          <div class="filter-content-wrapper">
            <div class="filter-header">
              <popup class="filter-popup-wrapper">
                <template #header>
                  <button class="filter-btn"><fa :icon="['far', 'file-lines']" /> <span id="selection">Regular</span><fa icon="angle-down" /></button>
                </template>
                <template #content>
                  <div class="display-selection-wrapper">
                    <span>
                      <input type="radio" name="trans_type" value="Regular" v-model="transType" @change="selectedType" id="regular" checked="checked" />
                      <fa class="checkmark" icon="check" />
                      <label for="regular">Regular</label>
                    </span>
                    <span>
                      <input type="radio" name="trans_type" value="Pending" v-model="transType" @change="selectedType" id="pending" />
                      <fa class="checkmark" icon="check" />
                      <label for="pending">Pending</label>
                    </span>
                  </div>
                </template>
              </popup>
              <button class="search-btn btn btn-square" @click="searchWithFilter"><fa icon="magnifying-glass"></fa></button>
            </div>

            <div class="calendar-wrapper">
              <VueDatePicker
                class="start-date"
                v-model="startDate"
                auto-apply
                :enable-time-picker="false"
                month-name-format="long"
                week-start="0"
                :day-names="['S', 'M', 'T', 'W', 'T', 'F', 'S']"
                format="MMM. dd, yyyy"
                placeholder="From"
              >
                <template #clear-icon></template>
              </VueDatePicker>

              <span v-if="startDate" class="start-btns">
                <button @click="deductStartDate(startDate)"><fa icon="angle-left" /></button>
                <button @click="addStartDate(startDate)"><fa icon="angle-right" /></button>
              </span>

              <VueDatePicker
                class="end-date"
                v-model="endDate"
                auto-apply
                :enable-time-picker="false"
                month-name-format="long"
                week-start="0"
                :day-names="['S', 'M', 'T', 'W', 'T', 'F', 'S']"
                format="MMM. dd, yyyy"
                placeholder="To"
              >
                <template #input-icon></template>
                <template #clear-icon></template>
              </VueDatePicker>

              <span v-if="endDate" class="end-btns">
                <button @click="deductEndDate(endDate)"><fa icon="angle-left" /></button>
                <button @click="addEndDate(endDate)"><fa icon="angle-right" /></button>
              </span>
            </div>

            <div v-if="transType == 'Regular'" class="filter-content-wrapper">
              <label class="filter-label">Search By</label>
              <label><span>Stn # </span><input type="text" v-model="stn" /></label>
              <label><span>Cashier #</span><input type="text" v-model="cashier" /></label>
              <label><span>Trans # </span><input type="text" v-model="transNum" /></label>
              <label><span>Auth # </span><input type="text" v-model="authno" /></label>

              <label class="filter-label">Transaction Total ($)</label>
              <span>
                <select v-model="comparedSign">
                  <option value="<">&lt;</option>
                  <option value="<=">&lt;=</option>
                  <option value="=">=</option>
                  <option value=">=">&gt;=</option>
                  <option value=">">&gt;</option>
                </select>
                <input type="text" v-model="comparedTotal" placeholder="0.00" />
              </span>
            </div>
          </div>
        </div>
      </div>
      <div class="content">
        <div v-if="regularTrans">
          <div v-if="!empty && transactions.length <= 0" class="no-results"><fa :icon="['fas', 'magnifying-glass']" />No search results found</div>
          <DataTable
            v-if="!empty && transactions.length > 0"
            id="rpt-table"
            class="tb-wrapper"
            :value="transactions"
            scrollable
            scrollHeight="760px"
            :virtualScrollerOptions="{ itemSize: 46 }"
            :exportFilename="fileName"
            ref="dt"
          >
            <template #header>
              <div class="table-header-wrapper">
                <div class="table-header">
                  <h3>All Transaction Report - {{ storeName }}</h3>
                  <p>As of date {{ formatDate(rptStartDate) }} - {{ formatDate(rptEndDate) }}</p>
                </div>
                <div class="table-btn-group">
                  <button class="print-btn btn btn-circle" onclick="window.print()"><fa icon="print"></fa></button>
                  <button class="excel-btn btn btn-circle" @click="exportCSV($event)"><fa icon="file-excel"></fa></button>
                </div>
              </div>
            </template>
            <Column field="station" header="Stn #"></Column>
            <Column field="trn_no" header="Trans #">
              <template #body="slotProps">
                <span class="trans-no">
                  {{ slotProps.data.trn_no }}
                  <button class="view-btn" @click="getTransDetail(slotProps.data.station, slotProps.data.trn_no)"><fa :icon="['far', 'eye']" /></button>
                </span>
              </template>
            </Column>
            <Column field="order_time" header="Date/Time">
              <template #body="slotProps">
                {{ formatDate(slotProps.data.order_time) }}
              </template>
            </Column>
            <Column field="auth_no" header="Auth #" />
            <Column field="cashier_no" header="Cashier" />
            <Column field="paytype" header="Paytype" />
            <Column field="discount" header="Discount" />
            <Column field="supervisor" header="Supervisor" />
            <Column field="amount" header="Amount ($)">
              <template #body="slotProps">
                {{ formatPrice(slotProps.data.amount) }}
              </template>
            </Column>
            <ColumnGroup type="footer">
              <Row>
                <Column footer="Number of Transactions:" :colspan="2" />
                <Column :footer="formatNumber(transCount)" footerStyle="text-align:left" />
                <Column footer="Total Amount:" :colspan="5" footerStyle="text-align:right" />
                <Column :footer="formatPrice(transTotal)" :colspan="2" />
              </Row>
            </ColumnGroup>
          </DataTable>

          <Transition name="fade">
            <div v-if="transDetail">
              <div class="overlay-black"></div>
              <div class="popup-wrapper">
                <div class="popup-header">
                  <p class="text">Transaction Detail</p>
                  <button class="close-btn" @click="closePopup"><fa icon="xmark" /></button>
                </div>
                <div class="trans-detail-wrapper">
                  <ul>
                    <li><span>Transaction #</span> {{ transactionDetailData.trn_no }}</li>
                    <li><span>Station #</span> {{ transactionDetailData.station }}</li>
                    <li><span>Amount</span> {{ formatPrice(transactionDetailData.amount) }}</li>
                    <li><span>Food Stamp</span> {{ formatPrice(transactionDetailData.fs_collect) }}</li>
                    <li><span>Debit Card</span> {{ formatPrice(transactionDetailData.debit) }}</li>
                    <li><span>Others</span> {{ formatPrice(transactionDetailData.other_amt) }}</li>
                    <li><span>Supervisor</span> {{ formatPrice(transactionDetailData.supervisor) }}</li>
                    <li><span>Payment Type</span> {{ transactionDetailData.paytype }}</li>
                    <li><span>Cashier</span> {{ transactionDetailData.cashier_no }}</li>
                    <li><span>Tax</span> {{ formatPrice(transactionDetailData.tax) }}</li>
                    <li><span>EBT Cash</span> {{ formatPrice(transactionDetailData.ebtcash) }}</li>
                    <li><span>Check</span> {{ formatPrice(transactionDetailData.check_pay) }}</li>
                    <li><span>Gift Card</span> {{ formatPrice(transactionDetailData.gift_card) }}</li>
                    <li><span>Auth. #</span> {{ transactionDetailData.auth_no }}</li>
                    <li><span>Date</span> {{ formatDate(transactionDetailData.order_time) }}</li>
                    <li><span>Discount</span> {{ formatPrice(transactionDetailData.discount) }}</li>
                    <li><span>Cash</span> {{ formatPrice(transactionDetailData.cash_pay) }}</li>
                    <li><span>Credit Card</span> {{ formatPrice(transactionDetailData.credit_amt) }}</li>
                    <li><span>Store Credit</span> {{ formatPrice(transactionDetailData.store_credit_amt) }}</li>
                    <div class="btn-group">
                      <button class="print-btn btn btn-circle" onclick="window.print()"><fa icon="print"></fa></button>
                      <button class="excel-btn btn btn-circle" @click="exportCSV($event)"><fa icon="file-excel"></fa></button>
                    </div>
                  </ul>
                </div>
                <DataTable id="rpt-table" class="m10" :value="transactionDetailData.details" scrollable scrollHeight="360px" :exportFilename="fileNameDetail" ref="dt">
                  <Column field="qty" header="Qty" />
                  <Column field="item_no" header="Item #" />
                  <Column field="item_amt" header="Amount ($)" class="amount">
                    <template #body="slotProps">
                      {{ formatPrice(slotProps.data.item_amt) }}
                    </template>
                  </Column>
                  <Column field="item_dep" header="Dep #" />
                  <Column field="name_desc" header="Name/Description" />
                  <Column field="pack" header="Pack" />
                  <Column field="weight" header="Weight (lb)" />
                  <Column field="misc" header="Misc" />
                  <Column field="msg" header="Message" />
                </DataTable>
              </div>
            </div>
          </Transition>
        </div>
        <div>
          <div v-if="pendingTrans">
            <div v-if="!empty && transactionsPending.length <= 0" class="no-results"><fa :icon="['fas', 'magnifying-glass']" />No search results found</div>
            <DataTable
              v-if="!empty && transactionsPending.length > 0"
              class="tb-wrapper"
              :value="transactionsPending"
              scrollable
              scrollHeight="760px"
              :virtualScrollerOptions="{ itemSize: 46 }"
              :exportFilename="fileName"
              ref="dt"
            >
              <template #header>
                <div class="table-header-wrapper">
                  <div class="table-header">
                    <h3>Pending Transaction Report - {{ storeName }}</h3>
                    <p>As of date {{ formatDate(rptStartDate) }} - {{ formatDate(rptEndDate) }}</p>
                  </div>
                  <div class="table-btn-group">
                    <button class="print-btn btn btn-circle" onclick="window.print()"><fa icon="print"></fa></button>
                    <button class="excel-btn btn btn-circle" @click="exportCSV($event)"><fa icon="file-excel"></fa></button>
                  </div>
                </div>
              </template>
              <Column field="order_time" header="Date/Time">
                <template #body="slotProps">
                  {{ formatDate(slotProps.data.order_time) }}
                </template>
              </Column>
              <Column field="station" header="Stn #" />
              <Column field="trn_no" header="Trans #">
                <template #body="slotProps">
                  <span class="trans-no">
                    {{ slotProps.data.trn_no }}
                    <button class="view-btn" @click="getTransDetail(slotProps.data.station, slotProps.data.trn_no)"><fa :icon="['far', 'eye']" /></button>
                  </span>
                </template>
              </Column>
              <Column field="cashier_no" header="Cashier" />
              <Column field="status" header="Status" />
              <Column field="total" header="Amount" class="amount">
                <template #body="slotProps">
                  {{ formatPrice(slotProps.data.total) }}
                </template>
              </Column>
              <Column field="deposit" header="Deposit"></Column>
              <ColumnGroup type="footer">
                <Row>
                  <Column footer="Number of Transactions:" :colspan="2" />
                  <Column :footer="formatNumber(transCount)" footerStyle="text-align:left" />
                  <Column footer="Total:" :colspan="2" footerStyle="text-align:right" />
                  <Column :footer="formatPrice(totalPendingTransAmount)" :colspan="1" />
                  <Column :footer="formatPrice(totalPendingTransDeposit)" :colspan="2" />
                </Row>
              </ColumnGroup>
            </DataTable>
            <Transition name="fade">
              <div v-if="transDetail">
                <div class="overlay-black"></div>
                <div class="popup-wrapper">
                  <div class="popup-header">
                    <p class="text">Pending Transaction Detail</p>
                    <button class="close-btn" @click="closePopup"><fa icon="xmark" /></button>
                  </div>
                  <div class="trans-detail-wrapper">
                    <ul>
                      <li><span>Transaction #</span> {{ transactionPendingDetailData.trn_no }}</li>
                      <li><span>Station #</span> {{ transactionPendingDetailData.station }}</li>
                      <li><span>Payment Type</span></li>
                      <li><span>Cashier</span> {{ transactionPendingDetailData.cashier_no }}</li>
                      <li><span>Date</span> {{ formatDate(transactionPendingDetailData.order_time) }}</li>
                      <li><span>Amount</span> {{ formatPrice(transactionPendingDetailData.total) }}</li>
                      <li><span>Deposit</span> {{ formatPrice(transactionPendingDetailData.deposit) }}</li>
                      <div class="btn-group">
                        <button class="print-btn btn btn-circle" onclick="window.print()"><fa icon="print"></fa></button>
                        <button class="excel-btn btn btn-circle" @click="exportCSV($event)"><fa icon="file-excel"></fa></button>
                      </div>
                    </ul>
                  </div>
                  <DataTable id="rpt-table" class="m10" :value="transactionPendingDetailData.posTrnsPendingDetails" scrollable scrollHeight="360px" :exportFilename="fileNameDetail" ref="dt">
                    <Column field="qty" header="Qty" />
                    <Column field="item_no" header="Item #" />
                    <Column field="price" header="Amount ($)" class="amount">
                      <template #body="slotProps">
                        {{ formatPrice(slotProps.data.price) }}
                      </template>
                    </Column>
                    <Column field="item_dep" header="Dep #" />
                    <Column field="name_desc" header="Name/Description" />
                    <Column field="pack" header="Pack" />
                    <Column field="weight" header="Weight (lb)" />
                    <Column field="misc" header="Misc" />
                    <Column field="msg" header="Message" />
                  </DataTable>
                </div>
              </div>
            </Transition>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
/* eslint-disable */
import Header from "@/components/Header.vue";
import axios from "axios";
import moment from "moment";
import { ref } from "vue";
import Popup from "@/components/Popup.vue";

export default {
  components: {
    Header,
    Popup,
  },
  setup() {
    const date = ref(0);
    const startTime = ref();
    const endTime = ref();

    return {
      date,
      startTime,
      endTime
    };
  },
  data() {
    return {
      isFilterActive: false,
      empty: true,
      loading: false,
      storeName: localStorage.getItem("StoreName"),
      transactions: [],
      transactionDetailData: [],
      transactionsPending: [],
      transactionPendingDetailData: [],
      transCount: "",
      transTotal: "",
      startDate: "",
      endDate: "",
      rptStartDate: "",
      rptEndDate: "",
      transDetail: "",
      transType: "Regular",
      regularTrans: true,
      pendingTrans: false,
      stn: "",
      cashier: "",
      transNum: "",
      comparedSign: "=",
      comparedTotal: "",
      authno: "",
    };
  },
  mounted() {},
  beforeMount() {
    window.addEventListener('click', this.close);
  },
  unmounted() {
    window.removeEventListener('click', this.close);
  },
  methods: {
    toggleFilter() {
      this.isFilterActive = !this.isFilterActive;
    },
    close(e) {
      if (!this.$refs.toggleFilter.contains(e.target)) {
        this.isFilterActive = false;
      }
    },
    formatPrice(value) {
      if (!value || value == 0) {
        return "0.00";
      }
      let val = (value / 1).toFixed(2).replace(",", ".");
      return val.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
    },
    formatNumber(value) {
      if (!value) {
        return 0;
      }
      return value.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
    },
    formatDate(date) {
      return moment(date).format("MMM. DD, yyyy");
    },
    addStartDate(date) {
      this.startDate = new Date(date.getTime() + 60 * 60 * 24 * 1000);
    },
    deductStartDate(date) {
      this.startDate = new Date(date.getTime() - 60 * 60 * 24 * 1000);
    },
    addEndDate(date) {
      this.endDate = new Date(date.getTime() + 60 * 60 * 24 * 1000);
    },
    deductEndDate(date) {
      this.endDate = new Date(date.getTime() - 60 * 60 * 24 * 1000);
    },
    exportCSV() {
      this.$refs.dt.exportCSV();
    },
    selectedType() {
      var value = "Nothing selected",
        selected = document.querySelector('input[name="trans_type"]:checked'),
        selection = document.querySelector("#selection");
      if (selected) {
        value = document.querySelector('label[for="' + selected.id + '"]').innerHTML;
      }
      selection.innerHTML = value;
    },
    searchWithFilter() {
      this.loading = true;
      this.isFilterActive = false;
      this.transactions = [];
      this.transactionsPending = [];

      if (this.startDate && this.endDate) {
        this.rptStartDate = moment(this.startDate).format("YYYY-MM-DD");
        this.rptEndDate = moment(this.endDate).format("YYYY-MM-DD");
      } else {
        this.rptStartDate = 0;
        this.rptEndDate = 0;
      }

      if (this.transType == "Regular") {
        this.regularTrans = true;
        this.pendingTrans = false;

        axios
          .get("https://cloudbackofficereportapidev.azurewebsites.net/Report/Transactions", {
            params: {
              sDate: this.rptStartDate,
              eDate: this.rptEndDate,
              stn: this.stn == "" ? 0 : this.stn,
              cashier: this.cashier == "" ? 0 : this.cashier,
              comparedTotal: this.comparedTotal,
              comparedSign: this.comparedSign,
              authno: this.authno,
              transCode: this.transNum,
            },
          })
          .then((response) => {
            this.transactions = response.data.datas.posTrnsLists;
            this.transCount = response.data.datas.transCount;
            this.transTotal = response.data.datas.transTotal;
          })
          .catch((error) => console.log(error.response))
          .finally(() => {
            this.loading = false;
            this.empty = false;
          });
      } else if (this.transType == "Pending") {
        this.regularTrans = false;
        this.pendingTrans = true;

        axios
          .get("https://cloudbackofficereportapidev.azurewebsites.net/Report/Transactions/Pending", {
            params: {
              sDate: this.rptStartDate,
              eDate: this.rptEndDate,
            },
          })
          .then((response) => {
            this.transactionsPending = response.data.datas;
            this.transCount = response.data.total;
          })
          .catch((error) => console.log(error.response))
          .finally(() => {
            this.loading = false;
            this.empty = false;
          });
      }
      
      this.startDate = "";
      this.endDate = "";
      this.stn = "";
      this.cashier = "";
      this.comparedTotal = "";
      this.comparedSign = "=";
      this.authno = "";
      this.transNum = "";
    },
    getTransDetail(stnNum, transNum) {
      if (stnNum < 10) {
        this.transDetail = "0" + stnNum + transNum;
      } else {
        this.transDetail = stnNum + transNum;
      }
      if (this.transType == "Regular") {
        axios
          .get("https://cloudbackofficereportapidev.azurewebsites.net/Report/Transactions/Detail/" + this.transDetail)
          .then((response) => {
            this.transactionDetailData = response.data.datas;
          })
          .catch((error) => console.log(error.response))
          .finally(() => (this.loading = false));
      } else if (this.transType == "Pending") {
        axios
          .get("https://cloudbackofficereportapidev.azurewebsites.net/Report/Transactions/Pending/Detail", {
            params: {
              stn: stnNum,
              trn_no: transNum,
            },
          })
          .then((response) => {
            this.transactionPendingDetailData = response.data.datas;
          })
          .catch((error) => console.log(error.response))
          .finally(() => (this.loading = false));
      }
    },
    closePopup() {
      return (this.transDetail = false);
    },
  },
  computed: {
    fileName() {
      let excelName = this.$route.name + " " + this.startDate + "-" + this.endDate;
      return excelName;
    },
    fileNameDetail() {
      let excelDetailName = "Transaction Detail";
      return excelDetailName;
    },
    totalPendingTransAmount() {
      let total = 0;
      for (let transactionPending of this.transactionsPending) {
        total += transactionPending.total;
      }
      return total;
    },
    totalPendingTransDeposit() {
      let total = 0;
      for (let transactionPending of this.transactionsPending) {
        total += transactionPending.deposit;
      }
      return total;
    },
  },
};
</script>
